SELECT 'Order' as "State", OrderH.REF as "Reference", OrderI.PRODUCT, OrderI.DESC1, OrderI.QUANTITY, OrderI.CUNIT, OrderI.PRICE as "Case_Price", OrderI.COST, OrderI.TOTNET as "Line_Value", OrderH.UF_ACCHAND as "IBM", OrderH.UF_EXPREPRODATE, OrderH.CONS1, OrderH.CONS2, OrderH.CONS3, OrderH.CONS4 FROM NISAINT_CS\OrderH OrderH LEFT JOIN OrderI ON OrderI.REF = OrderH.REF WHERE (OrderH.INSTATUS=1) AND (OrderH.OHINVREF Is Null) AND (OrderH.SEQTYPE In (11,14,41,31,96)) and (OrderH.OHSPLPRICEPOINT In ('2025-11-22', '2025-11-23', '2025-11-24')) Union SELECT 'Quote' as "State", QUOTEH.REF, QuoteI.PRODUCT, QuoteI.DESC1, QuoteI.QUANTITY, QuoteI.CUNIT, QuoteI.PRICE as "Case_Price", QuoteI.COST, QuoteI.TOTNET as "Line_Value", QuoteH.UF_ACCHAND as "IBM", QuoteH.UF_EXPREPRODATE, QuoteH.CONS1, QuoteH.CONS2, QuoteH.CONS3, QuoteH.CONS4 FROM NISAINT_CS\QUOTEH QUOTEH LEFT JOIN QuoteI ON QuoteI.REF = QuoteH.REF WHERE (QUOTEH.INSTATUS=1) AND (QUOTEH.QTRESULTORDERREF IS NULL) AND (QUOTEH.SEQTYPE In (11,14,41,31,96)) and (quoteH.OHSPLPRICEPOINT In ('2025-11-22', '2025-11-23', '2025-11-24'))
